<?php
namespace App\Domain\Combat;use App\Domain\Combat\Data\CombatAction;use App\Domain\Combat\Data\CombatCommand;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatStepResult;use App\Domain\Random\RandomNumberGenerator;use InvalidArgumentException;
final class CombatActionResolver {private $rng;public function __construct(RandomNumberGenerator $rng){$this->rng=$rng;}public function resolve(CombatState $state,CombatCommand $command):CombatStepResult{if($state->status()!==CombatStateStatus::IN_PROGRESS)throw new InvalidArgumentException('Combat already finished.');if($command->actionType()!==CombatActionType::BASIC_ATTACK)throw new InvalidArgumentException('Unsupported action.');$c=$state->character();$m=$state->monster();$ids=[$c->identifier(),$m->identifier()];if(!in_array($command->actorIdentifier(),$ids,true)||!in_array($command->targetIdentifier(),$ids,true)||$command->actorIdentifier()===$command->targetIdentifier())throw new InvalidArgumentException('Invalid participants.');if($command->actorIdentifier()!==$state->nextActorIdentifier())throw new InvalidArgumentException('Actor is out of turn.');$actor=$command->actorIdentifier()===$c->identifier()?$c:$m;$defender=$actor===$c?$m:$c;$expected=$defender->identifier();if($command->targetIdentifier()!==$expected)throw new InvalidArgumentException('Invalid target.');$before=$defender===$c?$state->characterCurrentHealth():$state->monsterCurrentHealth();$actorHealth=$actor===$c?$state->characterCurrentHealth():$state->monsterCurrentHealth();if($actorHealth<=0||$before<=0)throw new InvalidArgumentException('Defeated participant.');$chance=max(5,min(95,75+$actor->accuracyRate()-$defender->evasionRate()));$roll=$this->rng->randomInt(1,10000);$hit=$roll<=(int)round($chance*100);$cc=max(0,min(100,$actor->criticalChance()));$cr=null;$critical=false;$damage=0;if($hit){$cr=$this->rng->randomInt(1,10000);$critical=$cr<=(int)round($cc*100);$damage=max(1,(int)round($actor->attack()*(1-$defender->damageReductionRate()/100)*($critical?$actor->criticalDamageMultiplier():1)));}$after=max(0,$before-$damage);$ch=$state->characterCurrentHealth();$mh=$state->monsterCurrentHealth();if($defender===$c)$ch=$after;else$mh=$after;$status=CombatStateStatus::IN_PROGRESS;$next=null;$round=$state->roundNumber();if($mh===0)$status=CombatResultStatus::CHARACTER_VICTORY;elseif($ch===0)$status=CombatResultStatus::MONSTER_VICTORY;else{$first=$state->firstActorIdentifier();if($command->actorIdentifier()===$first)$next=$expected;else{$next=$first;$round++;}}$action=new CombatAction($state->roundNumber(),$actor->identifier(),$defender->identifier(),round($chance,2),$roll/100,$hit,round($cc,2),$cr===null?null:$cr/100,$critical,$damage,$before,$after);$nextState=new CombatState($c,$m,$ch,$mh,$round,$state->firstActorIdentifier(),$next,$status);return new CombatStepResult($state,$command,$action,$nextState);}}
